begin;
create table if not exists public.prediction_drift_reports(
 id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,window_days integer not null check(window_days in(30,60,90)),
 current_start timestamptz not null,current_end timestamptz not null,baseline_start timestamptz not null,baseline_end timestamptz not null,current_sample integer not null,baseline_sample integer not null,
 probability_psi numeric(10,6),score_mean_current numeric(8,3),score_mean_baseline numeric(8,3),conversion_rate_current numeric(8,3),conversion_rate_baseline numeric(8,3),brier_current numeric(10,6),brier_baseline numeric(10,6),
 drift_status text not null check(drift_status in('insufficient','stable','watch','alert')),signals jsonb not null default '[]'::jsonb,active_calibration_version integer,
 generated_by uuid not null references public.profiles(id),generated_at timestamptz not null default now()
);
create index if not exists prediction_drift_reports_latest_idx on public.prediction_drift_reports(organization_id,generated_at desc);
alter table public.prediction_drift_reports enable row level security;drop policy if exists prediction_drift_reports_scope on public.prediction_drift_reports;create policy prediction_drift_reports_scope on public.prediction_drift_reports for select to authenticated using(organization_id=(select public.current_organization_id()));revoke all on public.prediction_drift_reports from anon;revoke insert,update,delete on public.prediction_drift_reports from authenticated;grant select on public.prediction_drift_reports to authenticated;grant all on public.prediction_drift_reports to service_role;

create or replace function public.generate_prediction_drift_report(p_actor_id uuid,p_organization_id uuid,p_window_days integer default 30)
returns jsonb language plpgsql security definer set search_path='' as $$declare actor_role text;now_cutoff timestamptz:=date_trunc('hour',now());current_from timestamptz;baseline_from timestamptz;current_n integer:=0;baseline_n integer:=0;psi numeric;score_current numeric;score_baseline numeric;conversion_current numeric;conversion_baseline numeric;brier_now numeric;brier_before numeric;status_value text;signals_value jsonb:='[]'::jsonb;active_version integer;report_id uuid;
begin select coalesce(commercial_role,case role when'admin'then'director'else role end)into actor_role from public.profiles where id=p_actor_id and organization_id=p_organization_id and active=true;if actor_role not in('director','superintendent')then raise exception 'drift_actor_forbidden';end if;if p_window_days not in(30,60,90)then raise exception 'drift_window_invalid';end if;current_from:=now_cutoff-make_interval(days=>p_window_days);baseline_from:=current_from-make_interval(days=>p_window_days);
 with bucket as(select generate_series(0,9)b),current_counts as(select least(9,floor(predicted_probability/10)::integer)b,count(*)::numeric n from public.conversion_feature_snapshots where organization_id=p_organization_id and feature_cutoff_at>=current_from and feature_cutoff_at<now_cutoff group by 1),baseline_counts as(select least(9,floor(predicted_probability/10)::integer)b,count(*)::numeric n from public.conversion_feature_snapshots where organization_id=p_organization_id and feature_cutoff_at>=baseline_from and feature_cutoff_at<current_from group by 1),totals as(select(select count(*)from public.conversion_feature_snapshots where organization_id=p_organization_id and feature_cutoff_at>=current_from and feature_cutoff_at<now_cutoff)::numeric cn,(select count(*)from public.conversion_feature_snapshots where organization_id=p_organization_id and feature_cutoff_at>=baseline_from and feature_cutoff_at<current_from)::numeric bn),shares as(select greatest(coalesce(c.n,0)/greatest(t.cn,1),.0001)cs,greatest(coalesce(bc.n,0)/greatest(t.bn,1),.0001)bs from bucket k cross join totals t left join current_counts c on c.b=k.b left join baseline_counts bc on bc.b=k.b)
 select(select cn::integer from totals),(select bn::integer from totals),sum((cs-bs)*ln(cs/bs))into current_n,baseline_n,psi from shares;
 select avg((features->>'score')::numeric)filter(where feature_cutoff_at>=current_from and feature_cutoff_at<now_cutoff),avg((features->>'score')::numeric)filter(where feature_cutoff_at>=baseline_from and feature_cutoff_at<current_from)into score_current,score_baseline from public.conversion_feature_snapshots where organization_id=p_organization_id and feature_cutoff_at>=baseline_from and feature_cutoff_at<now_cutoff and(features->>'score')~'^\d+(\.\d+)?$';
 with labeled as(select s.feature_cutoff_at,s.predicted_probability::numeric,o.label_value::numeric label from public.conversion_feature_snapshots s join lateral(select x.label_value from public.conversion_outcome_labels x where x.organization_id=s.organization_id and x.lead_id=s.lead_id and x.outcome_at>s.feature_cutoff_at and x.outcome_at<=s.feature_cutoff_at+make_interval(days=>s.horizon_days)order by x.outcome_at limit 1)o on true where s.organization_id=p_organization_id and s.feature_cutoff_at>=baseline_from and s.feature_cutoff_at<now_cutoff)
 select avg(label)filter(where feature_cutoff_at>=current_from)*100,avg(label)filter(where feature_cutoff_at<current_from)*100,avg(power(predicted_probability/100-label,2))filter(where feature_cutoff_at>=current_from),avg(power(predicted_probability/100-label,2))filter(where feature_cutoff_at<current_from)into conversion_current,conversion_baseline,brier_now,brier_before from labeled;
 if current_n<100 or baseline_n<100 then status_value:='insufficient';signals_value:=signals_value||jsonb_build_array(jsonb_build_object('key','sample_low','severity','info'));else if psi>=.25 then signals_value:=signals_value||jsonb_build_array(jsonb_build_object('key','population_shift','severity','alert','value',round(psi,4)));elsif psi>=.10 then signals_value:=signals_value||jsonb_build_array(jsonb_build_object('key','population_shift','severity','watch','value',round(psi,4)));end if;if brier_now is not null and brier_before is not null and brier_now-brier_before>=.05 then signals_value:=signals_value||jsonb_build_array(jsonb_build_object('key','calibration_degradation','severity','alert','value',round(brier_now-brier_before,4)));elsif brier_now is not null and brier_before is not null and brier_now-brier_before>=.02 then signals_value:=signals_value||jsonb_build_array(jsonb_build_object('key','calibration_degradation','severity','watch','value',round(brier_now-brier_before,4)));end if;if conversion_current is not null and conversion_baseline is not null and abs(conversion_current-conversion_baseline)>=10 then signals_value:=signals_value||jsonb_build_array(jsonb_build_object('key','conversion_shift','severity','watch','value',round(conversion_current-conversion_baseline,2)));end if;status_value:=case when signals_value@>'[{"severity":"alert"}]'::jsonb then'alert'when jsonb_array_length(signals_value)>0 then'watch'else'stable'end;end if;
 select version into active_version from public.conversion_calibration_models where organization_id=p_organization_id and status='active'limit 1;insert into public.prediction_drift_reports(organization_id,window_days,current_start,current_end,baseline_start,baseline_end,current_sample,baseline_sample,probability_psi,score_mean_current,score_mean_baseline,conversion_rate_current,conversion_rate_baseline,brier_current,brier_baseline,drift_status,signals,active_calibration_version,generated_by)values(p_organization_id,p_window_days,current_from,now_cutoff,baseline_from,current_from,current_n,baseline_n,round(psi,6),round(score_current,3),round(score_baseline,3),round(conversion_current,3),round(conversion_baseline,3),round(brier_now,6),round(brier_before,6),status_value,signals_value,active_version,p_actor_id)returning id into report_id;
 return jsonb_build_object('reportId',report_id,'status',status_value,'currentSample',current_n,'baselineSample',baseline_n,'probabilityPsi',round(psi,6),'signals',signals_value,'humanReviewRequired',status_value in('watch','alert'),'automaticRollback',false,'automaticCampaignChange',false,'automaticPeopleDecision',false);
end $$;
revoke all on function public.generate_prediction_drift_report(uuid,uuid,integer)from public,anon,authenticated;grant execute on function public.generate_prediction_drift_report(uuid,uuid,integer)to service_role;
commit;
